export const AGENT_PLAN_CACHE_VERSION = 2;
const TOOL_CATEGORIES = ["action", "communication", "internal", "read"];
function isRecord(value) {
    return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}
function isToolCategory(value) {
    return typeof value === "string" && TOOL_CATEGORIES.includes(value);
}
function isPlanStep(value) {
    if (!isRecord(value))
        return false;
    return (typeof value.id === "string" &&
        typeof value.tool === "string" &&
        typeof value.label === "string" &&
        typeof value.description === "string" &&
        isToolCategory(value.category) &&
        typeof value.enabled === "boolean");
}
function isRawToolCall(value) {
    if (!isRecord(value))
        return false;
    return typeof value.id === "string" && typeof value.name === "string" && "input" in value;
}
function isStringRecord(value) {
    return isRecord(value) && Object.values(value).every(v => typeof v === "string");
}
function isAgentPlan(value) {
    if (!isRecord(value))
        return false;
    if (typeof value.instruction !== "string")
        return false;
    if (!Array.isArray(value.steps) || !value.steps.every(isPlanStep))
        return false;
    if (!Array.isArray(value.rawToolCalls) || !value.rawToolCalls.every(isRawToolCall))
        return false;
    if (value.readResults !== undefined && !isStringRecord(value.readResults))
        return false;
    if (value.warnings !== undefined && (!Array.isArray(value.warnings) || !value.warnings.every(w => typeof w === "string")))
        return false;
    return true;
}
export function readAgentPlanCacheRecordShape(value) {
    if (!isRecord(value))
        return null;
    if (value.version !== AGENT_PLAN_CACHE_VERSION ||
        typeof value.instruction !== "string" ||
        typeof value.settingsFingerprint !== "string" ||
        !isAgentPlan(value.plan)) {
        return null;
    }
    return {
        version: value.version,
        instruction: value.instruction,
        lastCustomerMessageId: typeof value.lastCustomerMessageId === "string" ? value.lastCustomerMessageId : null,
        settingsFingerprint: value.settingsFingerprint,
        plan: value.plan,
    };
}
function readAgentPlanCachePlan(value) {
    return readAgentPlanCacheRecordShape(value)?.plan ?? null;
}
// The reply text the agent drafted for this thread, pulled from the cached
// plan's send_reply call. Used as the "before" side of a brand-voice edit when
// the operator sends a different reply. Returns null when no draft is cached.
export function extractCachedDraftReply(cachedPlan) {
    const plan = readAgentPlanCachePlan(cachedPlan);
    if (!plan)
        return null;
    for (const call of plan.rawToolCalls) {
        if (call.name !== "send_reply")
            continue;
        const input = call.input;
        if (isRecord(input) && typeof input.text === "string" && input.text.trim()) {
            return input.text;
        }
    }
    return null;
}
export function getCurrentPlanForThread(thread, lastCustomerMessageId) {
    if (!thread.cachedPlanMessageId || thread.cachedPlanMessageId !== lastCustomerMessageId)
        return null;
    const plan = readAgentPlanCachePlan(thread.cachedPlan);
    return plan && plan.steps.length > 0 ? plan : null;
}
